 8→export async function transactions_table_exists(ctx: AssertionContext): Promise<AssertionResult> {
 9→  const rows = await queryRows<{ n: number }>(
10→    ctx,
11→    "SELECT count() AS n FROM system.tables WHERE database = 'analytics' AND name = 'transactions'",
12→  );
13→  const count = Number(rows[0]?.n ?? 0);
14→  const passed = count === 1;
15→  return {
16→    passed,
17→    message: passed ? "Transactions table exists." : `Expected 1 table, got ${count}.`,
18→    details: { count },
19→  };
20→}
