 5→  await ctx.pg.query("SELECT count(*) FROM app.transactions");
 6→  await ctx.clickhouse.query({
 7→    query: "SELECT count() FROM analytics.transactions",
 8→    format: "JSONEachRow",
 9→  });
10→  const elapsed = Date.now() - start;
11→  const passed = elapsed < 500;
12→  return {
